final:
module RefModule(  
    input wire clk,  
    input wire wr_en,  
    input wire [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] obf_memory;  

    always @(posedge clk) begin  
        if (wr_en) begin  
            obf_memory <= data_in;  
        end  
        data_out <= obf_memory;  
    end  
endmodule
